head.script:
(function(){
  const XHTML_NS="http://www.w3.org/1999/xhtml";
  const root=document.querySelector("foreignObject").firstElementChild;
  const head=root.querySelector("head");
  const body=root.querySelector("body");

  const originalCreateElement=document.createElement.bind(document);
  const originalCreateElementNS=document.createElementNS.bind(document);

  Object.defineProperty(document,"head",{get(){return head}});
  Object.defineProperty(document,"body",{get(){return body}});
  Object.defineProperty(document,"documentElement",{get(){return root}});

  document.createElement=function(tagName,options){
    if(typeof tagName==="string"){
      return originalCreateElementNS(XHTML_NS,tagName,options);
    }
    return originalCreateElement(tagName,options);
  };

  document.createElementNS=function(namespaceURI,qualifiedName,options){
    if(namespaceURI==null||namespaceURI===XHTML_NS){
      return originalCreateElementNS(XHTML_NS,qualifiedName,options);
    }
    return originalCreateElementNS(namespaceURI,qualifiedName,options);
  };
})();

body.script:
(async () => {
  const SOURCES = [
    "https://raw.githubusercontent.com/Darkdragonzxs/zd-pages/main/zodiac.html",
    "https://cdn.jsdelivr.net/gh/Darkdragonzxs/zd-pages@main/zodiac.html",
    "https://raw.githack.com/Darkdragonzxs/zd-pages/main/zodiac.html"
  ];

  let html = null;

  for (const url of SOURCES) {
    try {
      const res = await fetch(url);
      if (!res.ok) continue;
      html = await res.text();
      break;
    } catch {}
  }

  if (!html) {
    document.body.textContent = "failed to load";
    return;
  }

  html = html.replace(/<\/script>/gi, "</scr" + "ipt>");

  document.open();
  document.write(html);
  document.close();
})();
